<?php require_once __DIR__ . '/../includes/admin.php'; admin_required(); $counts=[]; foreach(['projects','gallery','enquiries','testimonials'] as $table){$counts[$table]=(int)db()->query("SELECT COUNT(*) FROM $table")->fetchColumn();} admin_head('Dashboard'); ?><h1>Welcome, <?=e($_SESSION['admin_name']??'Admin')?></h1><div class="grid"><?php foreach($counts as $name=>$count):?><div class="stat"><b><?=$count?></b><?=ucfirst($name)?></div><?php endforeach?></div><div class="card"><h2>Quick actions</h2><a class="button" href="<?=url('admin/add-project.php')?>">Add project</a> <a class="button" href="<?=url('admin/gallery.php')?>">Upload gallery image</a> <a class="button" href="<?=url('admin/enquiries.php')?>">View enquiries</a></div><?php admin_foot(); ?>
